import React, { useState, useRef, useCallback } from 'react';
import { Canvas, ControlPanel } from './components';
import { ddaLine, bresenhamLine, midpointCircle } from './algorithms';
import './App.css';

/**
 * Computer Graphics Algorithms Simulator
 * 
 * A React application that demonstrates classic computer graphics algorithms
 * for line and circle drawing with animated visualization.
 * 
 * Features:
 * - DDA Line Drawing Algorithm
 * - Bresenham's Line Drawing Algorithm
 * - Midpoint Circle Drawing Algorithm
 * - Animated pixel-by-pixel rendering
 * - Interactive parameter controls
 */
function App() {
  // Reference to the Canvas component for drawing operations
  const canvasRef = useRef(null);
  
  // Animation state
  const [isAnimating, setIsAnimating] = useState(false);
  const [animationSpeed, setAnimationSpeed] = useState(20);
  
  // Line drawing parameters
  const [lineParams, setLineParams] = useState({
    x1: -20,
    y1: -15,
    x2: 20,
    y2: 15
  });
  
  // Circle drawing parameters
  const [circleParams, setCircleParams] = useState({
    cx: 0,
    cy: 0,
    r: 15
  });
  
  // Drawing history for display
  const [drawHistory, setDrawHistory] = useState([]);
  
  /**
   * Add entry to drawing history
   */
  const addToHistory = (algorithm, params, pointCount) => {
    setDrawHistory(prev => [
      ...prev,
      {
        id: Date.now(),
        algorithm,
        params,
        pointCount,
        timestamp: new Date().toLocaleTimeString()
      }
    ].slice(-5)); // Keep last 5 entries
  };
  
  /**
   * Draw line using DDA algorithm
   */
  const handleDrawDDA = useCallback(async () => {
    if (!canvasRef.current || isAnimating) return;
    
    const { x1, y1, x2, y2 } = lineParams;
    
    setIsAnimating(true);
    
    // Generate points using DDA algorithm
    const points = ddaLine(x1, y1, x2, y2);
    
    // Animate the drawing with blue color
    await canvasRef.current.animatePoints(points, '#2196f3', animationSpeed);
    
    addToHistory('DDA Line', `(${x1},${y1}) → (${x2},${y2})`, points.length);
    setIsAnimating(false);
  }, [lineParams, isAnimating, animationSpeed]);
  
  /**
   * Draw line using Bresenham's algorithm
   */
  const handleDrawBresenham = useCallback(async () => {
    if (!canvasRef.current || isAnimating) return;
    
    const { x1, y1, x2, y2 } = lineParams;
    
    setIsAnimating(true);
    
    // Generate points using Bresenham's algorithm
    const points = bresenhamLine(x1, y1, x2, y2);
    
    // Animate the drawing with green color
    await canvasRef.current.animatePoints(points, '#4caf50', animationSpeed);
    
    addToHistory('Bresenham Line', `(${x1},${y1}) → (${x2},${y2})`, points.length);
    setIsAnimating(false);
  }, [lineParams, isAnimating, animationSpeed]);
  
  /**
   * Draw circle using Midpoint Circle algorithm
   */
  const handleDrawMidpointCircle = useCallback(async () => {
    if (!canvasRef.current || isAnimating) return;
    
    const { cx, cy, r } = circleParams;
    
    setIsAnimating(true);
    
    // Generate points using Midpoint Circle algorithm
    const points = midpointCircle(cx, cy, r);
    
    // Animate the drawing with purple color
    await canvasRef.current.animatePoints(points, '#9c27b0', animationSpeed);
    
    addToHistory('Midpoint Circle', `center(${cx},${cy}) r=${r}`, points.length);
    setIsAnimating(false);
  }, [circleParams, isAnimating, animationSpeed]);
  
  /**
   * Clear the canvas
   */
  const handleClear = useCallback(() => {
    if (canvasRef.current) {
      canvasRef.current.clear();
      setDrawHistory([]);
    }
  }, []);
  
  return (
    <div className="app">
      <header className="app-header">
        <h1>🎨 Computer Graphics Algorithms Simulator</h1>
        <p>Visualize classic rasterization algorithms with animated rendering</p>
      </header>
      
      <main className="app-main">
        <div className="canvas-section">
          <Canvas
            ref={canvasRef}
            width={600}
            height={600}
            pixelScale={10}
            showGrid={true}
          />
          
          {/* Drawing History */}
          {drawHistory.length > 0 && (
            <div className="history-panel">
              <h3>📝 Drawing History</h3>
              <ul>
                {drawHistory.map(entry => (
                  <li key={entry.id}>
                    <span className="history-time">{entry.timestamp}</span>
                    <span className="history-algo">{entry.algorithm}</span>
                    <span className="history-params">{entry.params}</span>
                    <span className="history-points">{entry.pointCount} pixels</span>
                  </li>
                ))}
              </ul>
            </div>
          )}
        </div>
        
        <ControlPanel
          lineParams={lineParams}
          setLineParams={setLineParams}
          circleParams={circleParams}
          setCircleParams={setCircleParams}
          onDrawDDA={handleDrawDDA}
          onDrawBresenham={handleDrawBresenham}
          onDrawMidpointCircle={handleDrawMidpointCircle}
          onClear={handleClear}
          isAnimating={isAnimating}
          animationSpeed={animationSpeed}
          setAnimationSpeed={setAnimationSpeed}
        />
      </main>
      
      {/* Animation indicator */}
      {isAnimating && (
        <div className="animation-indicator">
          <div className="spinner"></div>
          <span>Drawing in progress...</span>
        </div>
      )}
      
      <footer className="app-footer">
        <p>
          Built with React • Algorithms: DDA, Bresenham, Midpoint Circle
        </p>
      </footer>
    </div>
  );
}

export default App;
